static constexpr size_t ALL_CATEGORIES_COUNT = 43;

// ---- Accessor Functions ----

size_t DeviceDatabase::getCategoryCount() {
  return ALL_CATEGORIES_COUNT;
}

const char* DeviceDatabase::getCategoryName(size_t categoryIndex) {
  if (categoryIndex >= ALL_CATEGORIES_COUNT) return "";
  return ALL_CATEGORIES[categoryIndex].name;
}

size_t DeviceDatabase::getProfileCount(size_t categoryIndex) {
  if (categoryIndex >= ALL_CATEGORIES_COUNT) return 0;
  return ALL_CATEGORIES[categoryIndex].profileCount;
}

const DeviceProfileStatic* DeviceDatabase::getProfile(size_t categoryIndex, size_t profileIndex) {
  if (categoryIndex >= ALL_CATEGORIES_COUNT) return nullptr;
  const auto& cat = ALL_CATEGORIES[categoryIndex];
  if (profileIndex >= cat.profileCount) return nullptr;
  return &cat.profiles[profileIndex];
}

DeviceProfile DeviceDatabase::toDynamic(const DeviceProfileStatic* profile) {
  DeviceProfile dp;
  if (!profile) return dp;
  dp.brand = profile->brand;
  dp.protocol = profile->protocol;
  dp.address = profile->address;
  for (size_t i = 0; i < profile->commandCount; i++) {
    dp.commands.push_back({profile->commands[i].name, profile->commands[i].hexCode});
  }
  return dp;
}
